const input = $input.first().json;

const data =
  input.body && Object.keys(input.body).length > 0
    ? input.body
    : input.query && Object.keys(input.query).length > 0
      ? input.query
      : input;

const nombre = data.nombre || data.name || "";
const email = data.email || data.correo || "";
const telefono = data.telefono || data.phone || data.celular || "";
const empresa = data.empresa || data.company || "Sin empresa";
const fuente = data.fuente || data.source || "Sin fuente";
const mensaje = data.mensaje || data.message || "";

const leadId = "ADV-LEAD-" + Date.now();
const nombreLimpio = String(nombre).trim();

return [
  {
    json: {
      lead_id: leadId,
      nombre: nombreLimpio,
      email: String(email).toLowerCase().trim(),
      telefono: String(telefono).trim(),
      empresa: String(empresa).trim(),
      fuente: String(fuente).trim(),
      mensaje: String(mensaje).trim(),
      estado: "Procesado",
      fecha_registro: new Date().toISOString().slice(0, 10),
      folder_name: `ADV-${leadId} - ${nombreLimpio}`,
      json_original: JSON.stringify(data)
    }
  }
];

const item = $input.first().json;
const errores = [];

if (!item.nombre || item.nombre.trim().length < 2) {
  errores.push("Nombre inválido o vacío");
}

if (!item.email || !item.email.includes("@")) {
  errores.push("Email inválido o vacío");
}

if (!item.telefono || item.telefono.toString().length < 7) {
  errores.push("Teléfono inválido o vacío");
}

if (!item.mensaje || item.mensaje.trim().length < 5) {
  errores.push("Mensaje inválido o vacío");
}

return [
  {
    json: {
      ...item,
      valido: errores.length === 0,
      errores_validacion: errores
    }
  }
];

