const ai = $node['OpenAI - Clasificar Lead'].json;
let text = '';

if (ai.output_text) {
  text = ai.output_text;
} else if (ai.output?.[0]?.content?.[0]?.text) {
  text = ai.output[0].content[0].text;
} else if (ai.choices?.[0]?.message?.content) {
  text = ai.choices[0].message.content;
}

let parsed;
try {
  parsed = JSON.parse(text);
} catch (error) {
  parsed = {
    categoria: 'Otro',
    prioridad: 'Media',
    sentimiento: 'Neutral',
    resumen: 'No se pudo parsear correctamente la respuesta de la IA.',
    siguiente_accion: 'Revisar manualmente el lead.'
  };
}

const prioridad = parsed.prioridad || 'Media';
let tipoSeguimiento = 'Seguimiento estándar';
let diasContacto = 2;

if (prioridad === 'Alta') {
  tipoSeguimiento = 'Seguimiento urgente';
  diasContacto = 0;
} else if (prioridad === 'Media') {
  tipoSeguimiento = 'Seguimiento estándar';
  diasContacto = 2;
} else {
  tipoSeguimiento = 'Seguimiento de baja prioridad';
  diasContacto = 5;
}

const fecha = new Date();
fecha.setDate(fecha.getDate() + diasContacto);
const fechaSugerida = fecha.toISOString().slice(0, 10);

return [
  {
    json: {
      ...$node['Validar Datos'].json,
      categoria: parsed.categoria,
      prioridad,
      sentimiento: parsed.sentimiento,
      resumen: parsed.resumen,
      siguiente_accion: parsed.siguiente_accion,
      tipo_seguimiento: tipoSeguimiento,
      fecha_sugerida_contacto: fechaSugerida,
      task_id: 'TASK-' + Date.now(),
      ai_raw_response: JSON.stringify(ai)
    }
  }
];
